const assumptions = [
  { id: 'A001', assumption: 'Our primary buyers are engineering managers, not VPs', category: 'ICP', original_confidence: 'high', last_reviewed: '2025-10-01', evidence_at_creation: 'Based on 20 discovery calls in 2025 Q3 — 18/20 champions were engineering managers', new_evidence: 'Win/loss analysis (Q2 2026): 6 of last 10 enterprise wins had VP of Engineering as economic buyer, not manager' },
  { id: 'A002', assumption: 'Customers will not pay more than $500/month in SMB segment', category: 'Pricing', original_confidence: 'medium', last_reviewed: '2025-10-01', evidence_at_creation: 'Survey of 30 SMB prospects in 2025 — median WTP was $300/month', new_evidence: '3 SMB customers on $600/mo plan (launched Q1 2026). No churn after 6 months. N=3 so limited confidence.' },
  { id: 'A003', assumption: 'G2 reviews are the primary discovery channel for mid-market buyers', category: 'GTM', original_confidence: 'medium', last_reviewed: '2025-10-01', evidence_at_creation: 'Survey: 14/20 mid-market buyers said they checked G2 during evaluation', new_evidence: 'New survey (n=40, Q2 2026): G2 cited by 35%, peer referral cited by 42%. G2 still important but not primary.' },
  { id: 'A004', assumption: 'Integration quality is a top-3 purchase criterion for all segments', category: 'Product', original_confidence: 'high', last_reviewed: '2025-10-01', evidence_at_creation: 'Feature ranking survey 2025 — integrations ranked #2 overall', new_evidence: 'Feature ranking repeated Q1 2026 — integrations still #2 overall but #4 for SMB segment specifically' },
  { id: 'A005', assumption: 'The market will not see an AI-native entrant with traction before 2027', category: 'Competition', original_confidence: 'medium', last_reviewed: '2025-10-01', evidence_at_creation: 'No credible AI-native PM tool with >500 customers as of 2025', new_evidence: 'NewEntrant Co raised YC seed in July 2026. 200 waitlist signups. Too early to assess traction.' }
];
return [{ json: { assumptions, total: assumptions.length, review_date: new Date().toISOString() } }];

const { assumptions, total, review_date } = $input.first().json;
if (!assumptions || assumptions.length === 0) throw new Error('No assumptions to review');
const asText = assumptions.map((a, i) =>
  `[${i+1}] ID: ${a.id}\nAssumption: ${a.assumption}\nCategory: ${a.category}\nOriginal confidence: ${a.original_confidence}\nEvidence at creation: ${a.evidence_at_creation}\nNew evidence since last review: ${a.new_evidence}`
).join('\n\n');
const system = `You are a strategy consultant reviewing strategic assumptions. You assess whether new evidence confirms, weakens, or contradicts each assumption. You are honest about uncertainty. You flag any assumption that should change the strategy if it is wrong. Return ONLY valid JSON.`;
const user = `Re-assess these ${total} strategic assumptions against the new evidence provided.

Assumptions:
${asText}

Return JSON:
{
  "assessments": [
    {
      "id": "string",
      "assumption": "string",
      "verdict": "confirmed|weakened|contradicted|insufficient-evidence",
      "confidence_change": "increased|decreased|unchanged",
      "new_confidence": "low|medium|high",
      "reasoning": "string — specific reference to the evidence",
      "strategic_risk_if_wrong": "high|medium|low",
      "recommended_action": "string"
    }
  ],
  "assumptions_needing_action": number,
  "summary": "string — 2-3 sentences covering the most important finding"
}`;
return [{ json: { assumptions, total, review_date, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Audit Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.assessments || !Array.isArray(parsed.assessments)) {
  return [{ json: { _error: true, reason: 'Missing assessments array' } }];
}
return [{ json: { _error: false, audit: parsed, meta: { total: upstream.total, review_date: upstream.review_date } } }];

const { audit: a, meta: m } = $input.first().json;
const verdictLines = (a.assessments || []).map(ass =>
  `  [${ass.verdict.toUpperCase()}] ${ass.id}: ${ass.assumption}\n  Confidence: ${ass.new_confidence} (${ass.confidence_change}) | Risk if wrong: ${ass.strategic_risk_if_wrong}\n  Reasoning: ${ass.reasoning}\n  Action: ${ass.recommended_action}`
).join('\n\n');
const report = [
  `STRATEGY ASSUMPTION AUDIT`,
  `Review date: ${m.review_date} | Assumptions reviewed: ${m.total}`,
  `Needing action: ${a.assumptions_needing_action}`,
  ``,
  `SUMMARY: ${a.summary}`,
  ``,
  `ASSESSMENTS:`,
  verdictLines || '  (none)',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
